'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { User } from '@/types/database';
import { UserList } from '@/components/admin';
import { getCurrentUser, getAllUsers, changeUserPassword } from '@/app/actions/users';

export default function AdminPage() {
  const router = useRouter();
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function loadData() {
      try {
        const user = await getCurrentUser();
        if (!user || user.role !== 'admin') {
          router.push('/');
          return;
        }
        setCurrentUser(user);

        const allUsers = await getAllUsers();
        setUsers(allUsers);
      } catch (error) {
        console.error('Failed to load admin data:', error);
        router.push('/');
      } finally {
        setLoading(false);
      }
    }

    loadData();
  }, [router]);

  const handleChangePassword = async (userId: string, newPassword: string) => {
    await changeUserPassword(userId, newPassword);
  };

  if (loading) {
    return (
      <div className="flex flex-1 items-center justify-center bg-background">
        <div className="text-foreground-muted">Loading...</div>
      </div>
    );
  }

  if (!currentUser || currentUser.role !== 'admin') {
    return null;
  }

  return (
    <div className="flex flex-col flex-1 overflow-hidden bg-background">
      <main className="max-w-6xl mx-auto p-6">
        <div className="mb-8">
          <h1 className="text-xl lg:text-2xl font-bold text-foreground">User Management</h1>
          <p className="text-foreground-muted mt-1">
            Manage user accounts and passwords
          </p>
        </div>

        <UserList users={users} onChangePassword={handleChangePassword} />
      </main>
    </div>
  );
}


