    66	export async function createUploadSession(
    67	  packagingId: string,
    68	  files: { name: string; size: number; type: string; storagePath: string }[]
    69	): Promise<UploadSession> {
    70	  const supabase = await createClient();
    71	
    72	  const {
    73	    data: { user },
    74	  } = await supabase.auth.getUser();
    75	
    76	  if (!user) throw new Error('Not authenticated');
    77	
    78	  const { data: session, error: sessionError } = await supabase
    79	    .from('upload_sessions')
    80	    .insert({
    81	      packaging_id: packagingId,
    82	      uploaded_by: user.id,
    83	    })
    84	    .select()
    85	    .single();
    86	
    87	  if (sessionError) throw sessionError;
    88	
    89	  if (files.length > 0) {
    90	    const fileRecords = files.map((f) => ({
    91	      upload_session_id: session.id,
    92	      file_name: f.name,
    93	      file_size: f.size,
    94	      file_type: f.type,
    95	      storage_path: f.storagePath,
    96	    }));
    97	
    98	    const { error: filesError } = await supabase
    99	      .from('files')
   100	      .insert(fileRecords);
   101	
   102	    if (filesError) throw filesError;
   103	  }
   104	
   105	  // Update packaging item's updated_at and auto-transition status from 'new' to 'in_progress'
   106	  const { data: packagingItem } = await supabase
   107	    .from('items')
   108	    .select('status')
   109	    .eq('id', packagingId)
   110	    .single();
   111	
   112	  const updateData: { updated_at: string; status?: string } = {
   113	    updated_at: new Date().toISOString(),
   114	  };
   115	
   116	  // Only auto-transition from 'new' to 'in_progress'
   117	  if (packagingItem?.status === 'new') {
   118	    updateData.status = 'in_progress';
   119	  }
   120	
   121	  const { error: itemUpdateError } = await supabase
   122	    .from('items')
   123	    .update(updateData)
   124	    .eq('id', packagingId);
   125	
   126	  if (itemUpdateError) throw itemUpdateError;
   127	
   128	  revalidatePath('/');
   129	  return session;
   130	}
