   180	export async function deleteUploadSession(sessionId: string): Promise<void> {
   181	  const supabase = await createClient();
   182	
   183	  // Check if user is admin
   184	  const { data: { user } } = await supabase.auth.getUser();
   185	  if (!user) throw new Error('Not authenticated');
   186	
   187	  const { data: userData, error: userError } = await supabase
   188	    .from('users')
   189	    .select('role')
   190	    .eq('id', user.id)
   191	    .single();
   192	
   193	  if (userError) throw userError;
   194	  if (userData?.role !== 'admin') {
   195	    throw new Error('Only admins can delete upload sessions');
   196	  }
   197	
   198	  // Get files to delete from storage
   199	  const { data: files } = await supabase
   200	    .from('files')
   201	    .select('storage_path')
   202	    .eq('upload_session_id', sessionId);
   203	
   204	  if (files && files.length > 0) {
   205	    const paths = files.map((f) => f.storage_path);
   206	    const { error: storageError } = await supabase.storage.from('packaging-files').remove(paths);
   207	    if (storageError) throw storageError;
   208	  }
   209	
   210	  const { error } = await supabase
   211	    .from('upload_sessions')
   212	    .delete()
   213	    .eq('id', sessionId);
   214	
   215	  if (error) throw error;
   216	
   217	  revalidatePath('/');
   218	}

