    93	      file_size: f.size,
    94	      file_type: f.type,
    95	      storage_path: f.storagePath,
    96	    }));
    97	
    98	    const { error: filesError } = await supabase
    99	      .from('files')
   100	      .insert(fileRecords);
   101	
   102	    if (filesError) throw filesError;
   103	  }
   104	
